<template>
  <div>
    <el-tabs
      v-model="activeName"
      type="border-card"
      @tab-click="handleClick"
    >
      <div class="tip-info">
        <p>
          上傳文件如果有處理失敗的數據後將會生成錯誤文件，請及時查看錯誤訊息修改後重新下載，錯誤描述文件只保留<strong>15天</strong>。
        </p>
        <p>超過<strong>15天</strong>的錯誤描述文件將會刪除，不再提供下載查看</p>
      </div>
      <div
        v-for="item in pane_list"
        :key="item.label"
      >
        <el-tab-pane
          :label="item.label"
          :name="item.name"
        >
          <el-form
            ref="form"
            label-width="100px"
          >
            <div class="content-bottom-padded">
              <el-upload
                class="fl"
                style="margin-right: 10px"
                action=""
                :on-change="uploadHandleChange"
                :auto-upload="false"
                :show-file-list="false"
              >
                <el-button
                  size="small"
                  type="primary"
                >
                  點擊上傳
                </el-button>
              </el-upload>
              <el-button
                size="small"
                type="primary"
                @click="uploadHandleTemplate()"
              >
                下載模組
              </el-button>
            </div>
            <el-table
              v-loading="loading"
              :data="uploadList"
              :height="wheight - 220"
              element-loading-text="數據加載中"
            >
              <el-table-column
                prop="file_name"
                label="上傳文件"
                min-width="100"
              />
              <el-table-column
                prop="created_date"
                label="上傳時間"
                min-width="80"
              />
              <el-table-column
                prop="file_size_format"
                label="文件大小"
                min-width="60"
              />
              <el-table-column
                label="處理狀態"
                min-width="50"
              >
                <template slot-scope="scope">
                  <span v-if="scope.row.handle_status == 'wait'">等待處理</span>
                  <span v-if="scope.row.handle_status == 'processing'">處理中</span>
                  <span v-if="scope.row.handle_status == 'finish'">處理完成</span>
                </template>
              </el-table-column>
              <el-table-column
                prop="finish_date"
                label="處理完成時間"
              />
              <el-table-column label="處理成功">
                <template slot-scope="scope">
                  <span
                    v-if="scope.row.handle_message"
                  >{{ scope.row.handle_message.successLine }}行</span>
                </template>
              </el-table-column>
              <el-table-column label="處理失敗">
                <template slot-scope="scope">
                  <span
                    v-if="scope.row.handle_message"
                  >{{ scope.row.handle_message.errorLine }}行</span>
                  <a
                    v-if="scope.row.handle_message && scope.row.handle_message.errorLine > 0"
                    class="error_a"
                    type="primary"
                    @click="exportErrorFile(scope.row.id, scope.row.file_type)"
                  >下載錯誤詳情</a>
                </template>
              </el-table-column>
            </el-table>
            <div
              v-if="total_count > pageSize"
              class="content-top-padded content-center"
            >
              <el-pagination
                layout="total, prev, pager, next"
                :total="total_count"
                :page-size="pageSize"
                @current-change="handleCurrentChange"
              />
            </div>
          </el-form>
        </el-tab-pane>
      </div>
    </el-tabs>
  </div>
</template>
<script>
import { mapGetters } from 'vuex'
import {
  getTemplate,
  getFlieList,
  uploadFiles,
  exportUploadErrorFile
} from '@/api/productUpdate.js'

export default {
  data () {
    return {
      pane_list: [{ name: 'normal_goods', label: '上傳實體類商品' }],
      loading: false,
      total_count: 0,
      pageSize: 20,
      page: 1,
      activeName: 'normal_goods',
      uploadList: [],
      flie: {
        file_type: 'update_distribution_item',
        file_name: '更新店鋪商品'
      }
    }
  },
  computed: {
    ...mapGetters(['wheight'])
  },
  mounted () {
    this.getUploadList()
  },
  methods: {
    handleClick () {
      this.getUploadList()
    },
    // 上傳文件
    async uploadHandleChange (file, fileList) {
      console.log(file)
      console.log(fileList)
      let data = {
        isUploadFile: true,
        file_type: 'update_distribution_item',
        file: file.raw
      }

      await uploadFiles(data)
      this.$message({
        type: 'success',
        message: '上傳成功，等待處理'
      })
      this.getUploadList()
    },
    // 下載模組
    async uploadHandleTemplate () {
      try {
        const { status, data } = await getTemplate(this.flie)
        if (status === 200) {
          const a = document.createElement('a')
          a.href = data.data.file
          a.download = data.data.name
          document.body.appendChild(a)
          a.click()
          a.remove()
        }
      } catch (error) {
        this.$message({
          type: 'error',
          message: '沒有相關數據可匯出'
        })
      }
    },
    // 錯誤訊息
    async exportErrorFile (id, fileType) {
      let params = { file_type: fileType }
      try {
        const { data } = await exportUploadErrorFile(id, params)
        let a = document.createElement('a')
        a.href = data.data.file
        a.download = data.data.name
        document.body.appendChild(a)
        a.click()
        a.remove()
      } catch (error) {
        this.$message({
          type: 'error',
          message: '沒有相關數據可匯出'
        })
      }
    },
    handleCurrentChange (val) {
      this.page = val
      this.getUploadList()
    },
    // 獲取上傳文件列表
    async getUploadList () {
      this.loading = true
      let query = {
        file_type: this.flie.file_type,
        page: this.page,
        pageSize: this.pageSize
      }
      const { data, status } = await getFlieList(query)
      if (status === 200) {
        this.uploadList = data.data.list
        this.total_count = data.data.total_count
        this.loading = false
      }
    }
    // cellStyle(row,column,rowIndex,columnIndex){
    //     console.log(row.column);
    //     console.log(column);
    //     if (row.row.handle_status == 'processing') {
    //         return 'background:#FFB800'
    //     }else if(row.row.handle_status =='finish'){
    //          return 'background:#56BD6A'
    //     }else{
    //         return 'background:#E85E58'
    //     }

    // }
  }
}
</script>

